"use strict";parserFactory.register("volarenovels.com",()=>new VolarenovelsParser);class VolarenovelsParser extends Parser{constructor(){super()}async getChapterUrls(e){return[...e.querySelectorAll("ul.list-chapters a")].map(e=>util.hyperLinkToChapter(e))}findContent(e){return e.querySelector("div.panel-body div.fr-view")}extractTitleImpl(e){return e.querySelector("h3.title")}extractDescription(e){return e.querySelector("div#Details").textContent.trim()}findChapterTitle(e){return e.querySelector("div.panel-body h4")}findCoverImageUrl(e){return util.getFirstImgSrc(e,"div#content-container")}getInformationEpubItemChildNodes(e){return[...e.querySelectorAll("div#Details")]}}